  1→package email
  2→
  3→import (
  4→	"database/sql"
  5→	"encoding/json"
  6→	"fmt"
  7→	"strings"
  8→	"time"
  9→
 10→	gm "google.golang.org/api/gmail/v1"
 11→)
 12→
 13→type RawMessage struct {
 14→	ID          string
 15→	ThreadID    string
 16→	Subject     string
 17→	FromEmail   string
 18→	ToEmails    string // JSON array
 19→	CcEmails    string // JSON array
 20→	Date        string
 21→	Snippet     string
 22→	BodyPreview string
 23→	Labels      string // JSON array
 24→}
 25→
 26→type SyncResult struct {
 27→	Fetched  int
 28→	Stored   int
 29→	Cursor   string
 30→	Duration time.Duration
 31→}
 32→
 33→func Sync(srv *gm.Service, d *sql.DB) (*SyncResult, error) {
 34→	start := time.Now()
 35→	result := &SyncResult{}
 36→
 37→	var cursor string
 38→	d.QueryRow("SELECT sync_cursor FROM connectors WHERE id = 'gmail'").Scan(&cursor)
 39→
 40→	query := "in:sent"
 41→	if cursor == "" {
 42→		since := time.Now().AddDate(0, 0, -90).Format("2006/01/02")
 43→		query += " after:" + since
 44→	}
 45→
 46→	var pageToken string
 47→	for {
 48→		req := srv.Users.Messages.List("me").Q(query).MaxResults(100)
 49→		if pageToken != "" {
 50→			req = req.PageToken(pageToken)
 51→		}
 52→
 53→		resp, err := req.Do()
 54→		if err != nil {
 55→			return result, fmt.Errorf("listing messages: %w", err)
 56→		}
 57→
 58→		for _, msg := range resp.Messages {
 59→			result.Fetched++
 60→
 61→			if cursor != "" {
 62→				var exists int
 63→				d.QueryRow("SELECT 1 FROM emails WHERE id = ?", msg.Id).Scan(&exists)
 64→				if exists == 1 {
 65→					continue
 66→				}
 67→			}
 68→
 69→			full, err := srv.Users.Messages.Get("me", msg.Id).Format("metadata").
 70→				MetadataHeaders("Subject", "From", "To", "Cc", "Date").Do()
 71→			if err != nil {
 72→				fmt.Printf("  warning: skipping message %s: %v\n", msg.Id, err)
 73→				continue
 74→			}
 75→
 76→			email := parseMessage(full)
 77→			if err := StoreEmail(d, email); err != nil {
 78→				fmt.Printf("  warning: storing message %s: %v\n", msg.Id, err)
 79→				continue
 80→			}
 81→			result.Stored++
 82→		}
 83→
 84→		pageToken = resp.NextPageToken
 85→		if pageToken == "" {
 86→			break
 87→		}
 88→	}
 89→
 90→	result.Cursor = time.Now().UTC().Format(time.RFC3339)
 91→	result.Duration = time.Since(start)
 92→
 93→	d.Exec(
 94→		`INSERT INTO connectors (id, type, sync_cursor, last_sync_at, total_synced)
 95→		 VALUES ('gmail', 'email', ?, ?, ?)
 96→		 ON CONFLICT(id) DO UPDATE SET sync_cursor = ?, last_sync_at = ?, total_synced = total_synced + ?`,
 97→		result.Cursor, result.Cursor, result.Stored,
 98→		result.Cursor, result.Cursor, result.Stored,
 99→	)
100→
101→	return result, nil
102→}
103→
104→func StoreEmail(d *sql.DB, e *RawMessage) error {
105→	_, err := d.Exec(`
106→		INSERT INTO emails (id, thread_id, subject, from_email, to_emails, cc_emails, date, snippet, body_preview, labels)
107→		VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
108→		ON CONFLICT(id) DO UPDATE SET
109→			subject = excluded.subject,
110→			snippet = excluded.snippet,
111→			body_preview = excluded.body_preview,
112→			labels = excluded.labels,
113→			synced_at = datetime('now')`,
114→		e.ID, e.ThreadID, e.Subject, e.FromEmail, e.ToEmails, e.CcEmails,
115→		e.Date, e.Snippet, e.BodyPreview, e.Labels,
116→	)
117→	return err
118→}
119→
120→func parseMessage(msg *gm.Message) *RawMessage {
121→	e := &RawMessage{
122→		ID:       msg.Id,
123→		ThreadID: msg.ThreadId,
124→		Snippet:  msg.Snippet,
125→		CcEmails: "[]",
126→		ToEmails: "[]",
127→		Labels:   "[]",
128→	}
129→
130→	for _, h := range msg.Payload.Headers {
131→		switch h.Name {
132→		case "Subject":
133→			e.Subject = h.Value
134→		case "From":
135→			e.FromEmail = extractEmail(h.Value)
136→		case "To":
137→			e.ToEmails = emailsToJSON(h.Value)
138→		case "Cc":
139→			e.CcEmails = emailsToJSON(h.Value)
140→		case "Date":
141→			if t, err := time.Parse(time.RFC1123Z, h.Value); err == nil {
142→				e.Date = t.UTC().Format(time.RFC3339)
143→			} else if t, err := time.Parse("Mon, 2 Jan 2006 15:04:05 -0700", h.Value); err == nil {
144→				e.Date = t.UTC().Format(time.RFC3339)
145→			} else {
146→				e.Date = h.Value
147→			}
148→		}
149→	}
150→
151→	if len(msg.LabelIds) > 0 {
152→		labelsJSON, _ := json.Marshal(msg.LabelIds)
153→		e.Labels = string(labelsJSON)
154→	}
155→
156→	return e
157→}
158→
159→func extractEmail(header string) string {
160→	if i := strings.Index(header, "<"); i != -1 {
161→		if j := strings.Index(header, ">"); j != -1 {
162→			return header[i+1 : j]
163→		}
164→	}
165→	return strings.TrimSpace(header)
166→}
167→
168→func emailsToJSON(header string) string {
169→	if header == "" {
170→		return "[]"
171→	}
172→	parts := strings.Split(header, ",")
173→	emails := make([]string, 0, len(parts))
174→	for _, p := range parts {
175→		emails = append(emails, extractEmail(p))
176→	}
177→	data, _ := json.Marshal(emails)
178→	return string(data)
179→}
