 3→import "database/sql"
 4→
 5→type EmailStats struct {
 6→	Total        int            `json:"total"`
 7→	ByClass      map[string]int `json:"by_class"`
 8→	DateRange    DateRange      `json:"date_range"`
 9→	Unclassified int            `json:"unclassified"`
10→}
11→
12→type DateRange struct {
13→	Earliest string `json:"earliest"`
14→	Latest   string `json:"latest"`
15→}
16→
17→func Stats(d *sql.DB) (*EmailStats, error) {
18→	stats := &EmailStats{ByClass: make(map[string]int)}
19→
20→	d.QueryRow("SELECT COUNT(*) FROM emails").Scan(&stats.Total)
21→
22→	rows, err := d.Query("SELECT class, COUNT(*) FROM emails GROUP BY class")
23→	if err != nil {
24→		return nil, err
25→	}
26→	defer rows.Close()
27→
28→	for rows.Next() {
29→		var class string
30→		var count int
31→		rows.Scan(&class, &count)
32→		stats.ByClass[class] = count
33→		if class == "unclassified" {
34→			stats.Unclassified = count
35→		}
36→	}
37→
38→	d.QueryRow("SELECT MIN(date), MAX(date) FROM emails").Scan(&stats.DateRange.Earliest, &stats.DateRange.Latest)
39→
40→	return stats, nil
41→}
